// tracing.ts -- import this BEFORE any other module
import { NodeSDK } from '@opentelemetry/sdk-node';
import { getNodeAutoInstrumentations } from '@opentelemetry/auto-instrumentations-node';
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-grpc';
import { resourceFromAttributes } from '@opentelemetry/resources';
import { ATTR_SERVICE_NAME, ATTR_SERVICE_VERSION } from '@opentelemetry/semantic-conventions';

const sdk = new NodeSDK({
  resource: resourceFromAttributes({
    [ATTR_SERVICE_NAME]: process.env.OTEL_SERVICE_NAME || 'orders-api',
    [ATTR_SERVICE_VERSION]: process.env.APP_VERSION || '0.0.0',
  }),
  traceExporter: new OTLPTraceExporter({
    url: process.env.OTEL_EXPORTER_OTLP_ENDPOINT || 'http://otel-gateway:4317',
  }),
  instrumentations: [
    getNodeAutoInstrumentations({
      '@opentelemetry/instrumentation-fs': { enabled: false },
      '@opentelemetry/instrumentation-http': {
        ignoreIncomingRequestHook: (req) => req.url === '/health' || req.url === '/metrics',
      },
    }),
  ],
});

sdk.start();
process.on('SIGTERM', () => sdk.shutdown());

import { context, propagation, trace } from '@opentelemetry/api';

// Producer: inject trace context into message headers
async function publishOrder(order: Order) {
  const headers: Record<string, string> = {};
  propagation.inject(context.active(), headers);

  await producer.send({
    topic: 'orders.created',
    messages: [{
      key: order.id,
      value: JSON.stringify(order),
      headers,
    }],
  });
}

// Consumer: extract context and continue the trace
async function handleMessage(message: KafkaMessage) {
  const parentCtx = propagation.extract(context.active(), message.headers || {});
  const tracer = trace.getTracer('orders-worker');

  await context.with(parentCtx, async () => {
    await tracer.startActiveSpan('process-order', async (span) => {
      try {
        await processOrder(JSON.parse(message.value!.toString()));
      } finally {
        span.end();
      }
    });
  });
}

import { trace, SpanStatusCode } from '@opentelemetry/api';
import {
  ATTR_DB_SYSTEM_NAME,
  ATTR_DB_OPERATION_NAME,
  ATTR_DB_NAMESPACE,
} from '@opentelemetry/semantic-conventions';

const tracer = trace.getTracer('orders-api');

async function chargeCard(orderId: string, amountCents: number) {
  return tracer.startActiveSpan('payments.charge', async (span) => {
    span.setAttributes({
      'order.id': orderId,
      'payment.amount_cents': amountCents,
      'payment.currency': 'USD',
      [ATTR_DB_SYSTEM_NAME]: 'postgresql',
      [ATTR_DB_OPERATION_NAME]: 'INSERT',
      [ATTR_DB_NAMESPACE]: 'payments',
    });

    try {
      const result = await stripe.charges.create({ amount: amountCents });
      span.setStatus({ code: SpanStatusCode.OK });
      return result;
    } catch (err) {
      span.recordException(err as Error);
      span.setStatus({ code: SpanStatusCode.ERROR, message: (err as Error).message });
      throw err;
    } finally {
      span.end();
    }
  });
}

import { trace, context } from '@opentelemetry/api';
import pino from 'pino';

const baseLogger = pino({ level: 'info' });

function logger() {
  const span = trace.getSpan(context.active());
  if (!span) return baseLogger;

  const { traceId, spanId } = span.spanContext();
  return baseLogger.child({ trace_id: traceId, span_id: spanId });
}

// Usage anywhere in a request
logger().info({ orderId }, 'order created');
// {"level":"info","trace_id":"0af76519...","span_id":"b7ad6b71...","orderId":"o_123","msg":"order created"}
